function calculate({ filing_status, current_agi, current_itemized_deductions, current_long_term_capital_gains, proposed_ordinary_income_rate_change, proposed_standard_deduction_change, proposed_itemized_deduction_cap, proposed_capital_gains_rate_change, proposed_child_tax_credit_change }) {

    // Illustrative (simplified) 2023 Federal Income Tax Brackets (These are for demonstration, not exact current law)
    const TAX_RATES = {
        'single': [
            { bracket: 11600, rate: 0.10 },
            { bracket: 47150, rate: 0.12 },
            { bracket: 100525, rate: 0.22 },
            { bracket: 191950, rate: 0.24 },
            { bracket: 243725, rate: 0.32 },
            { bracket: 609350, rate: 0.35 },
            { bracket: Infinity, rate: 0.37 }
        ],
        'married_filing_jointly': [
            { bracket: 23200, rate: 0.10 },
            { bracket: 94300, rate: 0.12 },
            { bracket: 201050, rate: 0.22 },
            { bracket: 383900, rate: 0.24 },
            { bracket: 487450, rate: 0.32 },
            { bracket: 731200, rate: 0.35 },
            { bracket: Infinity, rate: 0.37 }
        ],
        'head_of_household': [
            { bracket: 16550, rate: 0.10 },
            { bracket: 63100, rate: 0.12 },
            { bracket: 100500, rate: 0.22 },
            { bracket: 191950, rate: 0.24 },
            { bracket: 243725, rate: 0.32 },
            { bracket: 609350, rate: 0.35 },
            { bracket: Infinity, rate: 0.37 }
        ]
    };

    // Illustrative (simplified) 2023 Standard Deductions
    const STANDARD_DEDUCTIONS = {
        'single': 13850,
        'married_filing_jointly': 27700,
        'head_of_household': 20800
    };

    const CHILD_TAX_CREDIT_BASE = 2000; // Illustrative base credit per child

    // Illustrative Long-Term Capital Gains rates thresholds (simplified based on ordinary income, not exact current law)
    const LTCG_THRESHOLDS = {
        '0%_cap': { single: 47050, mfj: 94100, hoh: 63050 }, // AGI (less LTCG) up to this amount gets 0% LTCG rate
        '15%_cap': { single: 518900, mfj: 583750, hoh: 549300 } // AGI (less LTCG) up to this amount gets 15% LTCG rate, above is 20%
    };

    // Helper function to calculate ordinary income tax using progressive brackets
    const calculateOrdinaryIncomeTax = (taxableIncome, taxBrackets) => {
        let tax = 0;
        let incomeToTax = Math.max(0, taxableIncome);

        for (let i = 0; i < taxBrackets.length; i++) {
            const { bracket, rate } = taxBrackets[i];
            const prevBracketThreshold = (i === 0) ? 0 : taxBrackets[i-1].bracket;
            const currentBracketWidth = bracket - prevBracketThreshold;

            if (incomeToTax <= 0) break;

            const incomeInThisBracket = Math.min(incomeToTax, currentBracketWidth);
            tax += incomeInThisBracket * rate;
            incomeToTax -= incomeInThisBracket;
        }
        return tax;
    };

    // Helper function to calculate Long-Term Capital Gains tax
    const calculateLTCGTax = (ltcgGains, ordinaryTaxableIncome, filingStatus, ltcgRatesAdjustment = 0) => {
        if (ltcgGains <= 0) return 0;

        let effectiveLTCGRate = 0;

        if (ordinaryTaxableIncome <= LTCG_THRESHOLDS['0%_cap'][filingStatus]) {
            effectiveLTCGRate = 0;
        } else if (ordinaryTaxableIncome <= LTCG_THRESHOLDS['15%_cap'][filingStatus]) {
            effectiveLTCGRate = 0.15;
        } else {
            effectiveLTCGRate = 0.20;
        }

        // Apply proposed change to the effective rate, ensuring it doesn't go below 0%
        effectiveLTCGRate = Math.max(0, effectiveLTCGRate + (ltcgRatesAdjustment / 100)); 

        return ltcgGains * effectiveLTCGRate;
    };


    // --- CURRENT TAX CALCULATION ---

    // 1. Determine Current Effective Deduction (Standard vs. Itemized)
    const currentStandardDeduction = STANDARD_DEDUCTIONS[filing_status] || 0;
    const effectiveCurrentDeduction = Math.max(currentStandardDeduction, current_itemized_deductions);

    // 2. Calculate Current Ordinary Taxable Income
    // AGI minus effective deduction, and separate out LTCG from the ordinary income stream
    const currentOrdinaryTaxableIncome = Math.max(0, current_agi - current_long_term_capital_gains - effectiveCurrentDeduction);

    // 3. Calculate Current Ordinary Income Tax
    const currentOrdinaryIncomeTax = calculateOrdinaryIncomeTax(currentOrdinaryTaxableIncome, TAX_RATES[filing_status]);

    // 4. Calculate Current Long-Term Capital Gains Tax
    const currentLTCGTax = calculateLTCGTax(current_long_term_capital_gains, currentOrdinaryTaxableIncome, filing_status);

    // 5. Calculate Current Total Tax before credits (simplified)
    let totalCurrentTaxBeforeCredits = currentOrdinaryIncomeTax + currentLTCGTax;

    // 6. Apply Current Child Tax Credit (simplified: assumes eligibility for base credit if children apply)
    // For this estimator, we assume the base credit applies and the change is an adjustment to it.
    let totalCurrentTax = Math.max(0, totalCurrentTaxBeforeCredits - CHILD_TAX_CREDIT_BASE);


    // --- PROPOSED TAX CALCULATION ---

    // 1. Determine Proposed Effective Deduction
    const proposedStandardDeduction = (STANDARD_DEDUCTIONS[filing_status] || 0) + proposed_standard_deduction_change;
    const proposedItemizedDeductions = Math.min(current_itemized_deductions, proposed_itemized_deduction_cap);
    const effectiveProposedDeduction = Math.max(proposedStandardDeduction, proposedItemizedDeductions);

    // 2. Calculate Proposed Ordinary Taxable Income
    const proposedOrdinaryTaxableIncome = Math.max(0, current_agi - current_long_term_capital_gains - effectiveProposedDeduction);

    // 3. Calculate Proposed Ordinary Income Tax
    // Deep copy current brackets and adjust rates
    let proposedOrdinaryTaxBrackets = JSON.parse(JSON.stringify(TAX_RATES[filing_status])); 
    proposedOrdinaryTaxBrackets = proposedOrdinaryTaxBrackets.map(bracket => ({ 
        ...bracket, 
        rate: Math.max(0, bracket.rate + (proposed_ordinary_income_rate_change / 100)) 
    }));
    const proposedOrdinaryIncomeTax = calculateOrdinaryIncomeTax(proposedOrdinaryTaxableIncome, proposedOrdinaryTaxBrackets);

    // 4. Calculate Proposed Long-Term Capital Gains Tax
    const proposedLTCGTax = calculateLTCGTax(current_long_term_capital_gains, proposedOrdinaryTaxableIncome, filing_status, proposed_capital_gains_rate_change);

    // 5. Calculate Proposed Total Tax before credits
    let totalProposedTaxBeforeCredits = proposedOrdinaryIncomeTax + proposedLTCGTax;

    // 6. Apply Proposed Child Tax Credit
    let proposedChildTaxCredit = CHILD_TAX_CREDIT_BASE + proposed_child_tax_credit_change;
    let totalProposedTax = Math.max(0, totalProposedTaxBeforeCredits - proposedChildTaxCredit);

    // --- FINAL IMPACT CALCULATION ---

    // A positive value means a tax cut (less owed), a negative value means a tax increase (more owed)
    const estimated_annual_tax_change = totalCurrentTax - totalProposedTax; 
    // A tax cut increases disposable income, an increase decreases it
    const net_disposable_income_change = -estimated_annual_tax_change; 

    return {
        estimated_annual_tax_change: parseFloat(estimated_annual_tax_change.toFixed(2)),
        net_disposable_income_change: parseFloat(net_disposable_income_change.toFixed(2))
    };
}
